    .max_tokens(100)
    .collect_text().await?;
ctx.flush().await?;
ctx.save("conv-42")?;                     // named KV snapshot

let mut ctx = Context::open(&model, "conv-42")?;
let before = ctx.seq_len();
ctx.user(&turn2).cue();                   // only new tokens enter buffer
let turn2_prefill = ctx.seq_len() - before + ctx.buffer().len() as u32;
